-- 误解本资产初始化数据：写作表达 / 固定搭配 / 易混词
-- 共 300 条，每类 100 条

DELETE p FROM `mistake_asset_progress` p
JOIN `mistake_asset_library` a ON a.`id` = p.`asset_id`
WHERE a.`category` IN ('writing', 'phrase', 'confusion');

DELETE FROM `mistake_asset_library` WHERE `category` IN ('writing', 'phrase', 'confusion');






